This issue still exists, and files continue to upload on `413` errors.

`$upload.upload().error()` is not called until the upload completes.  This is problematic if the server returns error `413` for a file that is too large for the server's setting. For example, if the default NGINX file upload size is 1MB and a user tries to upload a 15MB file, the user won't see the error and the file upload completes.

My solution was to add an event handler to intercept the server's any non-200 server responses and abort the upload.

```
var abortedXhr = null;
$upload.upload({
	url: '/api/upload/',
	'file': file
}).xhr(function(xhr){
	xhr.addEventListener("abort", function() {
		console.log('Main XHR request aborted.');
	});

	// xhr.upload.addEventListener("error", function() {});
	// xhr.upload.addEventListener("load", function() {});
	// xhr.upload.addEventListener("loadend", function() {});
	// xhr.upload.addEventListener("loadstart", function() {});
	// xhr.upload.addEventListener("timeout", function() {});
	xhr.upload.addEventListener("abort", function() {
		console.log('Upload XHR request aborted.');
	});
	xhr.upload.addEventListener("progress", function(progressEvent) {
		console.log('upload progress: '+parseInt(100.0 * progressEvent.loaded / progressEvent.total)+'%');
		if (xhr.readyState > 2 && xhr.status !== 0 && xhr.status !== 200) {
			// save the state of the faild request.  (i.e. 413 error codes and server error messages)
			abortedXhr = JSON.parse(JSON.stringify(xhr)); 

			xhr.abort();
		}
	})
}).error(function(e) {
	if(abortedXhr) {
		console.error('An error occurred during upload that prompted an abort');
		console.dir(abortedXhr);
	} else {
		console.error('An Error occurred during upload', e);
	}
}).success(function(e) {
	console.log('Upload successful.')
})
```

