Hi, @luochao1024  . it looks like that ParameterServer's update function never returns, so the other actors cannot get the resource. You can change your code as follows (Make ParameterServer's's update function return, and write another updater function to call this function periodically.):
```python
import ray
import time

ray.init(num_cpus=5)

@ray.remote
class ParameterServer:
    def __init__(self):
        self.global_steps = 0
        self.queue = []
        self.sum = 0

    def push(self, value):
        print("called")
        self.queue.append(value)
        print('push function is working, the len of the queue is', len(self.queue))
        return 0

    def update(self):
        if len(self.queue) > 0:
            value = self.queue.pop(0)
            self.sum += value
            self.global_steps += 1
            print('ps is working')
        else:
            print('weired')

@ray.remote
def worker(ps, worker_index):
    for i in range(50):
        result = ray.get(ps.push.remote(1))
        print('worker is working')
    return result

@ray.remote
def updater(ps, interation):
    for i in range(interation):
        ps.update.remote()
        time.sleep(1)
    return result


ps = ParameterServer.remote()
worker_tasks = [worker.remote(ps, i) for i in range(4)]
worker_tasks.append(updater.remote(ps, 10))
ray.wait(worker_tasks, num_returns=5)

```

